//this function contains ajax call to node.js webservice called WEBSERVICENAME
var ProcessFunction = function () {
  VV.Form.ShowLoadingPanel();
  //This gets all of the form fields.
  var formData = VV.Form.getFormDataCollection();
  console.log("formData", formData);

  //Following will prepare the collection and send with call to server side script.
  var data = JSON.stringify(formData);
  var requestObject = $.ajax({
    type: "POST",
    url:
      VV.BaseAppUrl +
      "api/v1/" +
      VV.CustomerAlias +
      "/" +
      VV.CustomerDatabaseAlias +
      "/scripts?name=postRevision", // Nombre del WS
    contentType: "application/json; charset=utf-8",
    data: data,
    success: "",
    error: "",
  });
  return requestObject;
};

VV.Form.ShowLoadingPanel();

$.when(ProcessFunction()).always(function (resp) {
  VV.Form.HideLoadingPanel();
  var messageData = "";
  if (typeof resp.status != "undefined") {
    messageData =
      "A status code of " +
      resp.status +
      " returned from the server.  There is a communication problem with the  web servers.  If this continues, please contact the administrator and communicate to them this message and where it occurred.";
    //VV.Form.Global.DisplayMessaging(messageData);
    alert(messageData);
  } else if (typeof resp.statusCode != "undefined") {
    messageData =
      "A status code of " +
      resp.statusCode +
      " with a message of '" +
      resp.errorMessages[0].message +
      "' returned from the server.  This may mean that the servers to run the business logic are not available.";
    //VV.Form.Global.DisplayMessaging(messageData);
    alert(messageData);
  } else if (resp.meta.status == "200") {
    if (resp.data[0] != "undefined") {
      if (resp.data[0] == "Success") {
        //Do Successful Actions Here
        alert("ok");
        //Postback save should always be the last thing that happens.
      } else if (resp.data[0] == "Error") {
        messageData = "An error was encountered. " + resp.data[1];
        //VV.Form.Global.DisplayMessaging(messageData);
        alert(messageData);
      } else {
        messageData =
          "An unhandled response occurred.  The form will not save at this time.  Please try again or communicate this issue to support.";
        //VV.Form.Global.DisplayMessaging(messageData);
        alert(messageData);
      }
    } else {
      messageData = "The status of the response returned as undefined.";
      //VV.Form.Global.DisplayMessaging(messageData);
      alert(messageData);
    }
  } else {
    messageData =
      "The following error(s) were encountered: " + resp.data.error + "<br>";
    //VV.Form.Global.DisplayMessaging(messageData);
    alert(messageData);
  }
});

// PROCESS NAME for TEMPLATE NAME

var webSeviceName = 'getForms';
var formName = 'Name of the form';
var message; // the message is set below

VV.Form.ShowLoadingPanel();

function CallServerSide() {
    // Get all the form fields data
    var formData = VV.Form.getFormDataCollection();

    // Uncomment the following to add more data to the formData object.
    // var moreData = {
    //    name: 'This is the name you will use on getFieldValueByName',
    //    value: "Here goes the value"
    // };
    // formData.push(moreData);

    // Parse the data as a JSON string
    var data = JSON.stringify(formData);

    var requestObject = $.ajax({
        type: 'POST',
        url: VV.BaseAppUrl + 'api/v1/' + VV.CustomerAlias + '/' + VV.CustomerDatabaseAlias + '/scripts?name=' + webSeviceName,
        contentType: 'application/json; charset=utf-8',
        data: data,
        success: '',
        error: '',
    });

    return requestObject;
}

$.when(CallServerSide())
    .always(function (resp) {
        var errorOnConexion = typeof resp.status != 'undefined';
        var errorOnServer = typeof resp.statusCode != 'undefined';
        var serverSentOKResponse = resp.meta.status == '200';
        var wsSentResponse = resp.data[0] != undefined;
        var wsSentSuccessResponse = resp.data[0] == 'Success';
        var wsSentErrorResponse = resp.data[0] == 'Error';

        if (errorOnConexion) {
            message =
                'A status code of ' +
                resp.status +
                ' returned from the server.  There is a communication problem with the web servers.  If this continues, please contact the administrator and communicate to them this message and where it occurred.';
        } else if (errorOnServer) {
            message =
                'A status code of ' +
                resp.statusCode +
                " with a message of '" +
                resp.errorMessages[0].message +
                "' returned from the server.  This may mean that the servers to run the business logic are not available.";
        } else if (serverSentOKResponse) {
            if (wsSentResponse) {
                if (wsSentSuccessResponse) {
                    message = formName + ' has been saved successfully.';

                    // HANDLE SUCCESS RESPONSE HERE

                    // Alway use .then for waiting for the form to save before running another function
                    VV.Form.DoAjaxFormSave();
                } else if (wsSentErrorResponse) {
                    message = 'An error was encountered. ' + resp.data[1];
                } else {
                    message =
                        'An unhandled response occurred when calling ' +
                        webSeviceName +
                        '. The form will not save at this time.  Please try again or communicate this issue to support.';
                }
            } else {
                message = 'The status of the response returned as undefined.';
            }
        } else {
            message = 'The following unhandled response occurred while attempting to retrieve data on the the server side get data logic.' + resp.data.error + '<br>';
        }
    })
    .then(function () {
        VV.Form.Global.DisplayMessaging(message, formName);
        VV.Form.HideLoadingPanel();
    });

